//
                (function () {
                    function fillPageVars() {
                        var vars = {};
                        var query = window.location.search.substring(1).split('&');
                        for (var i = 0; i < query.length; i++) {
                            var pair = query[i].split('=', 2);
                            vars[pair[0]] = decodeURIComponent(pair[1] || '');
                        }
                        var keys = ['page', 'topage', 'frompage', 'webpage', 'section', 'subsection', 'subsubsection'];
                        for (var k = 0; k < keys.length; k++) {
                            var els = document.getElementsByClassName(keys[k]);
                            for (var j = 0; j < els.length; j++) {
                                els[j].textContent = vars[keys[k]] || els[j].textContent || '';
                            }
                        }
                    }
                    if (document.readyState === 'loading') {
                        document.addEventListener('DOMContentLoaded', fillPageVars);
                    } else {
                        fillPageVars();
                    }
                })();
//
